import type { MessageNormalizer } from '../../normalization/pipeline';
import { parseNumeric } from '../../normalization/pipeline';
import type { NormalizedOHLCV, NormalizedOrderbook, NormalizedTick, NormalizedTrade } from '../../types/normalized';
import type {
  OkxCandleEntry,
  OkxOrderbookEntry,
  OkxRawMessage,
  OkxRestCandle,
  OkxTickerEntry,
  OkxTradeEntry,
} from './okx-types';

/**
 * Normalizes raw OKX V5 WebSocket and REST messages.
 *
 * Handles:
 * - ALL fields are strings (even numeric ones) -- parseFloat everywhere
 * - Candle data as positional arrays
 * - BTC-USDT -> BTC/USDT symbol normalization
 * - Dual WebSocket (public + business) message routing
 * - CRC32 checksum field tracking for order book validation
 */
export class OkxNormalizer implements MessageNormalizer<OkxRawMessage> {
  parseMessage(raw: string): OkxRawMessage | undefined {
    // OKX sends literal "pong" text responses
    if (raw === 'pong') return undefined;

    try {
      const parsed: unknown = JSON.parse(raw);
      if (typeof parsed !== 'object' || parsed === null) return undefined;

      // Skip subscription confirmations and error responses
      if ('event' in parsed) return undefined;

      // Must have arg and data fields
      if (!('arg' in parsed && 'data' in parsed)) return undefined;

      return parsed as OkxRawMessage;
    } catch {
      return undefined;
    }
  }

  normalizeTicker(raw: OkxRawMessage): NormalizedTick | undefined {
    if (raw.arg.channel !== 'tickers') return undefined;
    const entry = raw.data[0];
    if (!entry || !this.isTickerEntry(entry)) return undefined;

    const lastPrice = parseNumeric(entry.last);
    const openPrice = parseNumeric(entry.open24h);
    const priceChange = lastPrice - openPrice;
    const priceChangePercent = openPrice !== 0 ? (priceChange / openPrice) * 100 : 0;
    const symbol = this.normalizeSymbol(entry.instId);

    return {
      symbol,
      lastPrice,
      priceChange,
      priceChangePercent,
      high24h: parseNumeric(entry.high24h),
      low24h: parseNumeric(entry.low24h),
      volume24h: parseNumeric(entry.vol24h),
      quoteVolume24h: parseNumeric(entry.volCcy24h),
      timestamp: parseNumeric(entry.ts),
      bestBid: parseNumeric(entry.bidPx),
      bestBidQty: parseNumeric(entry.bidSz),
      bestAsk: parseNumeric(entry.askPx),
      bestAskQty: parseNumeric(entry.askSz),
    };
  }

  normalizeTrade(raw: OkxRawMessage): NormalizedTrade | undefined {
    if (raw.arg.channel !== 'trades') return undefined;
    const entry = raw.data[0];
    if (!entry || !this.isTradeEntry(entry)) return undefined;

    return {
      id: entry.tradeId,
      timestamp: parseNumeric(entry.ts),
      price: parseNumeric(entry.px),
      quantity: parseNumeric(entry.sz),
      side: entry.side,
      buyerMaker: entry.side === 'sell',
    };
  }

  normalizeOHLCV(raw: OkxRawMessage): NormalizedOHLCV | undefined {
    // Candle channels start with "candle" (e.g., "candle1m", "candle1H")
    if (!raw.arg.channel.startsWith('candle')) return undefined;
    const entry = raw.data[0];
    if (!entry || !this.isCandleEntry(entry)) return undefined;

    return {
      timestamp: parseNumeric(entry[0]),
      open: parseNumeric(entry[1]),
      high: parseNumeric(entry[2]),
      low: parseNumeric(entry[3]),
      close: parseNumeric(entry[4]),
      volume: parseNumeric(entry[5]),
      quoteVolume: parseNumeric(entry[7]),
      tradeCount: 0,
      closed: entry[8] === '1',
    };
  }

  normalizeOrderbook(raw: OkxRawMessage): NormalizedOrderbook | undefined {
    // Order book channels start with "books" (e.g., "books", "books5", "books50-l2-tbt")
    if (!raw.arg.channel.startsWith('books')) return undefined;
    const entry = raw.data[0];
    if (!entry || !this.isOrderbookEntry(entry)) return undefined;

    const symbol = this.normalizeSymbol(raw.arg.instId ?? '');

    return {
      symbol,
      timestamp: parseNumeric(entry.ts),
      bids: entry.bids.map(([price, qty]) => ({
        price: parseNumeric(price),
        quantity: parseNumeric(qty),
      })),
      asks: entry.asks.map(([price, qty]) => ({
        price: parseNumeric(price),
        quantity: parseNumeric(qty),
      })),
      sequenceId: entry.seqId ?? 0,
      type: raw.action === 'snapshot' ? 'snapshot' : 'delta',
    };
  }

  /** Normalize a REST candle (positional array) into NormalizedOHLCV. */
  normalizeRestCandle(candle: OkxRestCandle): NormalizedOHLCV {
    return {
      timestamp: parseNumeric(candle[0]),
      open: parseNumeric(candle[1]),
      high: parseNumeric(candle[2]),
      low: parseNumeric(candle[3]),
      close: parseNumeric(candle[4]),
      volume: parseNumeric(candle[5]),
      quoteVolume: parseNumeric(candle[7]),
      tradeCount: 0,
      closed: candle[8] === '1',
    };
  }

  /**
   * Compute CRC32 checksum from top 25 bid/ask levels.
   * OKX format: bid1_price:bid1_size:ask1_price:ask1_size:...
   */
  computeChecksum(bids: ReadonlyArray<readonly [string, string, string, string]>, asks: ReadonlyArray<readonly [string, string, string, string]>): number {
    const parts: string[] = [];
    const maxLevels = Math.min(25, Math.max(bids.length, asks.length));

    for (let i = 0; i < maxLevels; i++) {
      const bid = bids[i];
      if (bid) {
        parts.push(`${bid[0]}:${bid[1]}`);
      }
      const ask = asks[i];
      if (ask) {
        parts.push(`${ask[0]}:${ask[1]}`);
      }
    }

    return this.crc32(parts.join(':'));
  }

  /** Standard CRC32 computation. */
  private crc32(str: string): number {
    let crc = -1;
    for (let i = 0; i < str.length; i++) {
      const byte = str.charCodeAt(i);
      crc = (crc >>> 8) ^ (CRC32_TABLE[(crc ^ byte) & 0xff] ?? 0);
    }
    return (crc ^ -1) >>> 0;
  }

  private normalizeSymbol(instId: string): string {
    return instId.replace('-', '/');
  }

  private isTickerEntry(entry: unknown): entry is OkxTickerEntry {
    return typeof entry === 'object' && entry !== null && 'instId' in entry && 'last' in entry;
  }

  private isTradeEntry(entry: unknown): entry is OkxTradeEntry {
    return typeof entry === 'object' && entry !== null && 'tradeId' in entry && 'px' in entry;
  }

  private isCandleEntry(entry: unknown): entry is OkxCandleEntry {
    return Array.isArray(entry) && entry.length >= 9;
  }

  private isOrderbookEntry(entry: unknown): entry is OkxOrderbookEntry {
    return typeof entry === 'object' && entry !== null && 'asks' in entry && 'bids' in entry;
  }
}

/** Pre-computed CRC32 lookup table. */
const CRC32_TABLE: number[] = (() => {
  const table: number[] = [];
  for (let i = 0; i < 256; i++) {
    let crc = i;
    for (let j = 0; j < 8; j++) {
      crc = crc & 1 ? (crc >>> 1) ^ 0xedb88320 : crc >>> 1;
    }
    table.push(crc >>> 0);
  }
  return table;
})();
